                    "title": "qBotica in the Community",
                    "class_name": "",
                    "grid_items": "2",
                    "description": "qBotica actively supports the community by providing mentoring, internships, and partnerships with entrepreneur organizations and college universities. Our aim is to promote innovation and education in the field of <a href=\"/what-is-robotic-process-automation/\">robotics process automation (RPA)</a> and Intelligent Automation.",
                    "display_options": "a:4:{i:0;s:10:\"main_title\";i:1;s:11:\"description\";i:2;s:5:\"image\";i:3;s:10:\"grid_items\";}",
